parameters.jsCode:
const form = $input.first().json;
if (form['Contraseña de operador'] !== 'CrackTesos2026_Admin') {
  throw new Error('Contraseña incorrecta.');
}
const question = form['Pregunta']?.trim();
const correct = form['Respuesta CORRECTA']?.trim();
const wrong1 = form['Respuesta incorrecta 1']?.trim();
const wrong2 = form['Respuesta incorrecta 2']?.trim();
if (!question || !correct || !wrong1 || !wrong2) throw new Error('Faltan campos obligatorios.');

// Validar y convertir fecha (Bogotá → UTC)
const rawDate = form['Fecha y hora de envío Bogotá (AAAA-MM-DD HH:MM)']?.trim();
if (!rawDate || !/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/.test(rawDate)) {
  throw new Error('Formato de fecha incorrecto. Usa: AAAA-MM-DD HH:MM');
}
// Convertir Bogotá (UTC-5) a UTC
const sentAtUTC = new Date(rawDate.replace(' ', 'T') + ':00-05:00').toISOString();
const closesAtUTC = new Date(new Date(sentAtUTC).getTime() + 24 * 3600 * 1000).toISOString();

// Mostrar en Bogotá para confirmación
const sentAtBogota = new Date(sentAtUTC).toLocaleString('es-CO', {timeZone: 'America/Bogota'});
const closesAtBogota = new Date(closesAtUTC).toLocaleString('es-CO', {timeZone: 'America/Bogota'});

// Shuffle A/B/C
const options = [{text: correct, is_correct: true}, {text: wrong1, is_correct: false}, {text: wrong2, is_correct: false}];
for (let i = options.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [options[i], options[j]] = [options[j], options[i]];
}
const correct_option = options[0].is_correct ? 'A' : (options[1].is_correct ? 'B' : 'C');

return [{json: {
  action: form['Acción'],
  trivia_number: parseInt(form['Número de trivia']),
  question,
  correct_answer: correct,
  wrong_1: wrong1,
  wrong_2: wrong2,
  option_a: options[0].text,
  option_b: options[1].text,
  option_c: options[2].text,
  correct_option,
  sent_at_utc: sentAtUTC,
  closes_at_utc: closesAtUTC,
  sent_at_bogota: sentAtBogota,
  closes_at_bogota: closesAtBogota,
  has_multiplier: form['¿Tiene goles adicionales (multiplicador)?'] === 'Sí' ? 'true' : 'false',
  status: form['Estado'] || 'draft'
}}];
